@prefix cdif: <https://cdif.org/0.1/> .
@prefix rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#> .
@prefix schema1: <http://schema.org/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <https://example.org/var/temperature> ;
            sh:resultMessage "For data description level, a cdi:InstanceVariable should specify cdif:physicalDataType." ;
            sh:resultPath cdif:physicalDataType ;
            sh:resultSeverity sh:Warning ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "For data description level, a cdi:InstanceVariable should specify cdif:physicalDataType." ;
                    sh:minCount 1 ;
                    sh:or ( [ sh:nodeKind sh:IRI ] [ sh:datatype xsd:string ;
                                sh:minLength 3 ] [ sh:class schema1:DefinedTerm ] ) ;
                    sh:path cdif:physicalDataType ;
                    sh:severity sh:Warning ] ] .

